import React, { useMemo, useEffect, useRef, useState } from "react";
import Grid from "./components/Grid/Grid";
import Lightbox from "./components/Lightbox/Lightbox";
import Header from "./components/Header/Header";
import Filters from "./components/Filters/Filters";
import { getImage } from "./utils/getImage";
import { Helmet, HelmetProvider } from "react-helmet-async";
import usePortfolio from "./hooks/usePortfolio";
import data from "./data/portfolio.json";

/* =========================
   DATA PREPARATION (OK fuera)
========================= */
const rawItems = data.items;
const { temas, tags, usos } = data.dicts;

const items = rawItems.map((item) => {
  const temasLabels = item.meta.temas.map((i) => temas[i]);
  const tagsLabels = item.meta.tags.map((i) => tags[i]);
  const usosLabels = item.meta.usos.map((i) => usos[i]);

  const allFilters = [...temasLabels, ...tagsLabels, ...usosLabels];
  const allFiltersLower = allFilters.map((f) => f.toLowerCase());

  let categoria = item.categoria;
  if (categoria === "otros") {
    if (item.id.startsWith("ilu-")) categoria = "ilustracion";
    else if (item.id.startsWith("dis-")) categoria = "diseno";
  }

  return {
    ...item,
    categoria,
    temasLabels,
    tagsLabels,
    usosLabels,
    allFilters,
    allFiltersLower,
  };
});

/* =========================
   COMPONENTE
========================= */
export default function Portfolio() {
  /* UI STATE (🔴 ahora bien dentro) */
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const [openPanel, setOpenPanel] = useState(null);
  const [hovered, setHovered] = useState(null);
  const [zoom, setZoom] = useState(false);
  const [gridTransition, setGridTransition] = useState(true);

  const gridScrollRef = useRef(0);

  /* PORTFOLIO STATE */
  const {
    query,
    setQuery,
    category,
    setCategory,
    filters,
    setFilters,
    filtered,
    paginated,
    page,
    setPage,
    selected,
    setSelected,
    pageSize,
  } = usePortfolio();

  const options = useMemo(() => {
    const set = new Set();
    items.forEach((item) => {
      item.allFilters.forEach((f) => set.add(f));
    });
    return Array.from(set).sort();
  }, []);

  const Pagination = () => {
  if (filtered.length <= pageSize) return null;

  return (
    <div style={{
      textAlign: "center",
      display: "flex",
      justifyContent: "center",
      gap: "12px",
      margin: "10px 0",
    }}>
      <button
        onClick={() => setPage(p => p - 1)}
        disabled={page === 1}
      >
        ←
      </button>

      <span>
        {page} / {Math.ceil(filtered.length / pageSize)}
      </span>

      <button
        onClick={() => setPage(p => p + 1)}
        disabled={page * pageSize >= filtered.length}
      >
        →
      </button>
    </div>
  );
};

  /* DERIVADOS */
  const pageSelected =
    paginated.find((item) => item.id === selected?.id) || null;

  const isSingle = filtered.length <= 2;

  /* =========================
     EFFECTS
  ========================= */

  // precarga imágenes
  useEffect(() => {
    if (!selected) return;
    const index = filtered.findIndex((i) => i.id === selected.id);

    const next = filtered[index + 1];
    if (next) new Image().src = getImage(next, "full");

    const prev = filtered[index - 1];
    if (prev) new Image().src = getImage(prev, "full");
  }, [selected, filtered]);

  // transición grid
  useEffect(() => {
    setGridTransition(false);
    setPage(1);
    const t = setTimeout(() => setGridTransition(true), 150);
    return () => clearTimeout(t);
  }, [filtered, setPage]);

  // scroll lock lightbox
  useEffect(() => {
    if (lightboxOpen) {
      gridScrollRef.current = window.scrollY;
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }
    return () => {
      document.body.style.overflow = "auto";
    };
  }, [lightboxOpen]);

  // URL hash
  useEffect(() => {
    if (selected) {
      window.history.replaceState(null, "", `#${selected.id}`);
    }
  }, [selected]);

  useEffect(() => {
    const hash = window.location.hash.replace("#", "");
    if (hash) {
      const found = items.find((item) => item.id === hash);
      if (found) setSelected(found);
    }
  }, [setSelected]);

  /* =========================
     HANDLERS (mínimos)
  ========================= */

  const changeSelected = (item) => {
    setSelected(item);
    setLightboxOpen(true);
  };

  const goNext = () => {
    if (!selected) return;
    const index = filtered.findIndex((i) => i.id === selected.id);
    if (filtered[index + 1]) setSelected(filtered[index + 1]);
  };

  const goPrev = () => {
    if (!selected) return;
    const index = filtered.findIndex((i) => i.id === selected.id);
    if (filtered[index - 1]) setSelected(filtered[index - 1]);
  };

  /* =========================
     RENDER
  ========================= */

  return (
    <HelmetProvider>
      <div>
        <Helmet>
          <title>{selected ? selected.titulo : "Marist-Art"}</title>
        </Helmet>

        {/* HEADER limpio */}
        <Header
          query={query}
          setQuery={setQuery}
          category={category}
          setCategory={setCategory}
          filters={filters}
          setFilters={setFilters}
          filteredCount={filtered.length}
          searchOpen={searchOpen}
          setSearchOpen={setSearchOpen}
          openPanel={openPanel}
          setOpenPanel={setOpenPanel}
          onLogoClick={() => {
            setQuery("");
            setCategory("todas");
            setFilters([]);
            setSelected(null);
          }}
        />
        <Filters
          filters={filters}
          setFilters={setFilters}
          options={options}
        />

        {/* GRID */}
        <div
          style={{
            padding: "12px 20px",
            opacity: gridTransition ? 1 : 0,
            transition: "opacity 0.2s ease",
          }}
        >
          {filtered.length === 0 && (
            <div style={{ textAlign: "center", color: "white" }}>
              Sin resultados
            </div>
          )}
          <Pagination />

          <Grid
            items={paginated}
            selectedId={pageSelected?.id}
            onSelect={changeSelected}
            hoveredId={hovered}
            setHovered={setHovered}
            isSingle={isSingle}
          />

          <Pagination />

        </div>

        {/* LIGHTBOX */}
        <Lightbox
          selected={selected}
          isOpen={lightboxOpen}
          onClose={() => {
            setZoom(false);
            setLightboxOpen(false);
            setSelected(null);
            setTimeout(() => {
              window.scrollTo({ top: gridScrollRef.current });
            }, 50);
          }}
          onNext={goNext}
          onPrev={goPrev}
          zoom={zoom}
          setZoom={setZoom}
        />
      </div>
    </HelmetProvider>
  );
}
